import{_ as e,o as l,c as d,ag as a}from"./chunks/framework.DTiDeF2Q.js";const g=JSON.parse('{"title":"기본 별칭 | Dotfiles (KO)","titleTemplate":":title","description":"탐색, 시스템 제어 및 일상 작업을 위한 필수 셸 별칭. 범용 단축키로 터미널 워크플로를 단순화합니다.","frontmatter":{"title":"기본 별칭 | Dotfiles","description":"탐색, 시스템 제어 및 일상 작업을 위한 필수 셸 별칭. 범용 단축키로 터미널 워크플로를 단순화합니다.","lang":"ko-KR","author":"Sebastien Rousseau","lastUpdated":true,"image":"/logo.png","imageAlt":"기본 별칭 preview","canonical":"/ko/aliases/default/","robots":"index, follow","draft":false,"noindex":false,"sitemap":true,"breadcrumbTitle":"기본 별칭","pageType":"docs","schemaType":"WebPage","metaTitle":"기본 별칭 - Dotfiles (KR)","permalink":"/ko/aliases/default/","sidebar":true,"meta":[{"name":"keywords","content":"default aliases, shell aliases, terminal shortcuts, dotfiles, bash aliases"},{"name":"twitter:card","content":"summary"},{"name":"twitter:title","content":"기본 별칭 - Dotfiles"},{"name":"twitter:description","content":"탐색, 시스템 제어 및 일상 작업을 위한 필수 셸 별칭."},{"name":"og:title","content":"기본 별칭 - Dotfiles"},{"name":"og:description","content":"탐색, 시스템 제어 및 일상 작업을 위한 필수 셸 별칭."},{"name":"og:image:alt","content":"Dotfiles - 셸 라이프에 맞게 간단하게 설계됨"},{"name":"og:locale","content":"ko_KR"}]},"headers":[],"relativePath":"ko/aliases/default/index.md","filePath":"ko/aliases/default/index.md","lastUpdated":1773010926000}'),o={name:"ko/aliases/default/index.md"};function i(n,t,s,c,r,f){return l(),d("div",null,[...t[0]||(t[0]=[a('<h1 id="기본-별칭" tabindex="-1">기본 별칭 <a class="header-anchor" href="#기본-별칭" aria-label="Permalink to &quot;기본 별칭&quot;">​</a></h1><p>일상적인 터미널 작업을 위한 필수 셸 단축키.</p><h2 id="개요" tabindex="-1">개요 <a class="header-anchor" href="#개요" aria-label="Permalink to &quot;개요&quot;">​</a></h2><p>기본 별칭은 일반적인 터미널 작업을 간소화하는 범용 셸 단축키 모음을 제공합니다. 이 별칭은 <code>default.aliases.sh</code>에 정의되어 있으며 chezmoi에 의해 지원되는 모든 셸에서 자동으로 로드됩니다.</p><p>이 단축키는 일반 유틸리티, 종료 명령, 네트워크 진단, 시스템 모니터링 및 파일 시스템 탐색을 다룹니다.</p><h2 id="참조" tabindex="-1">참조 <a class="header-anchor" href="#참조" aria-label="Permalink to &quot;참조&quot;">​</a></h2><h3 id="일반" tabindex="-1">일반 <a class="header-anchor" href="#일반" aria-label="Permalink to &quot;일반&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">별칭</th><th style="text-align:left;">명령</th><th style="text-align:left;">설명</th></tr></thead><tbody><tr><td style="text-align:left;"><code>da</code></td><td style="text-align:left;"><code>date &quot;+%Y-%m-%d %A %T %Z&quot;</code></td><td style="text-align:left;">현재 날짜 및 시간 표시</td></tr><tr><td style="text-align:left;"><code>p</code></td><td style="text-align:left;"><code>pwd</code></td><td style="text-align:left;">작업 디렉토리 출력</td></tr><tr><td style="text-align:left;"><code>path</code></td><td style="text-align:left;"><code>echo ${PATH//:/\\\\n}</code></td><td style="text-align:left;">PATH 변수를 새 줄에 표시</td></tr><tr><td style="text-align:left;"><code>r</code></td><td style="text-align:left;"><code>reload</code></td><td style="text-align:left;">셸 다시 로드</td></tr><tr><td style="text-align:left;"><code>t</code></td><td style="text-align:left;"><code>tail -f</code></td><td style="text-align:left;">실시간으로 파일 출력 추적</td></tr><tr><td style="text-align:left;"><code>wk</code></td><td style="text-align:left;"><code>date +%V</code></td><td style="text-align:left;">현재 주 번호 표시</td></tr></tbody></table><h3 id="종료-및-셧다운" tabindex="-1">종료 및 셧다운 <a class="header-anchor" href="#종료-및-셧다운" aria-label="Permalink to &quot;종료 및 셧다운&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">별칭</th><th style="text-align:left;">명령</th><th style="text-align:left;">설명</th></tr></thead><tbody><tr><td style="text-align:left;"><code>q</code></td><td style="text-align:left;"><code>exit</code></td><td style="text-align:left;">셸 종료</td></tr><tr><td style="text-align:left;"><code>quit</code></td><td style="text-align:left;"><code>exit</code></td><td style="text-align:left;">셸 종료</td></tr><tr><td style="text-align:left;"><code>bye</code></td><td style="text-align:left;"><code>exit</code></td><td style="text-align:left;">셸 종료</td></tr><tr><td style="text-align:left;"><code>:q</code></td><td style="text-align:left;"><code>exit</code></td><td style="text-align:left;">셸 종료 (vim 스타일)</td></tr><tr><td style="text-align:left;"><code>halt</code></td><td style="text-align:left;"><code>sudo /sbin/halt</code></td><td style="text-align:left;">시스템 중지</td></tr><tr><td style="text-align:left;"><code>poweroff</code></td><td style="text-align:left;"><code>sudo /sbin/shutdown</code></td><td style="text-align:left;">시스템 전원 끄기</td></tr><tr><td style="text-align:left;"><code>reboot</code></td><td style="text-align:left;"><code>sudo /sbin/reboot</code></td><td style="text-align:left;">시스템 재부팅</td></tr></tbody></table><h3 id="히스토리" tabindex="-1">히스토리 <a class="header-anchor" href="#히스토리" aria-label="Permalink to &quot;히스토리&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">별칭</th><th style="text-align:left;">명령</th><th style="text-align:left;">설명</th></tr></thead><tbody><tr><td style="text-align:left;"><code>h</code></td><td style="text-align:left;"><code>history</code></td><td style="text-align:left;">명령 히스토리 보기</td></tr><tr><td style="text-align:left;"><code>history</code></td><td style="text-align:left;"><code>fc -il 1</code></td><td style="text-align:left;">ISO 8601 타임스탬프로 히스토리 표시</td></tr></tbody></table><h3 id="네트워크" tabindex="-1">네트워크 <a class="header-anchor" href="#네트워크" aria-label="Permalink to &quot;네트워크&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">별칭</th><th style="text-align:left;">명령</th><th style="text-align:left;">설명</th></tr></thead><tbody><tr><td style="text-align:left;"><code>ifconfig</code></td><td style="text-align:left;"><code>sudo ifconfig</code></td><td style="text-align:left;">네트워크 인터페이스 구성</td></tr><tr><td style="text-align:left;"><code>ipinfo</code></td><td style="text-align:left;"><code>ipconfig getpacket en0</code></td><td style="text-align:left;">en0의 네트워크 파라미터 가져오기</td></tr><tr><td style="text-align:left;"><code>nls</code></td><td style="text-align:left;"><code>sudo lsof -i -P | grep LISTEN</code></td><td style="text-align:left;">활성 네트워크 리스너 표시</td></tr><tr><td style="text-align:left;"><code>op</code></td><td style="text-align:left;"><code>sudo lsof -i -P</code></td><td style="text-align:left;">열린 포트 나열</td></tr><tr><td style="text-align:left;"><code>ping</code></td><td style="text-align:left;"><code>ping -c 5</code></td><td style="text-align:left;">5개 패킷 제한으로 ping</td></tr><tr><td style="text-align:left;"><code>ports</code></td><td style="text-align:left;"><code>netstat -tulan</code></td><td style="text-align:left;">모든 리스닝 포트 나열</td></tr></tbody></table><h3 id="시스템-모니터링" tabindex="-1">시스템 모니터링 <a class="header-anchor" href="#시스템-모니터링" aria-label="Permalink to &quot;시스템 모니터링&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">별칭</th><th style="text-align:left;">명령</th><th style="text-align:left;">설명</th></tr></thead><tbody><tr><td style="text-align:left;"><code>top</code></td><td style="text-align:left;"><code>sudo btop</code></td><td style="text-align:left;">대화형 프로세스 모니터</td></tr><tr><td style="text-align:left;"><code>spd</code></td><td style="text-align:left;"><code>sudo rm -rf /private/var/log/asl/*</code></td><td style="text-align:left;">ASL 로그 파일 정리</td></tr></tbody></table><h3 id="유틸리티" tabindex="-1">유틸리티 <a class="header-anchor" href="#유틸리티" aria-label="Permalink to &quot;유틸리티&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">별칭</th><th style="text-align:left;">명령</th><th style="text-align:left;">설명</th></tr></thead><tbody><tr><td style="text-align:left;"><code>ctf</code></td><td style="text-align:left;"><code>ls -1 | wc -l</code></td><td style="text-align:left;">현재 디렉토리의 파일 수</td></tr><tr><td style="text-align:left;"><code>qfind</code></td><td style="text-align:left;"><code>find . -name</code></td><td style="text-align:left;">빠른 파일 검색</td></tr><tr><td style="text-align:left;"><code>reload</code></td><td style="text-align:left;"><code>exec $SHELL -l</code></td><td style="text-align:left;">셸 다시 로드</td></tr><tr><td style="text-align:left;"><code>wth</code></td><td style="text-align:left;"><code>curl -s &quot;wttr.in/?format=3&quot;</code></td><td style="text-align:left;">현재 날씨 가져오기</td></tr></tbody></table>',18)])])}const y=e(o,[["render",i]]);export{g as __pageData,y as default};
